import os
path = r'C:\Users\Revexn\Desktop\antigravity\seconde-exp'
skip = {'.venv', '.pytest_cache', '__pycache__', 'node_modules', '.git', '.github'}
for root, dirs, files in os.walk(path):
    dirs[:] = [d for d in dirs if d not in skip]
    for f in files:
        fp = os.path.join(root, f)
        ext = f.lower().split('.')[-1] if '.' in f else ''
        if ext in ('env', 'json', 'txt', 'py', 'cfg', 'ini', 'yaml', 'yml', 'toml', 'bat', 'md') or f.startswith('.env'):
            print(f'FILE: {fp} (size={os.path.getsize(fp)})')
